python -c "
from outlines.prompts import prompt, register_filter, unregister_filter, Prompt

register_filter('shout', lambda x: x.upper() + '!')

@prompt
def greet(name):
    '''Hello {{ name | shout }}'''

print(greet('world'))

unregister_filter('shout')
try:
    print(greet('world'))
except Exception as e:
    print('after unregister ->', type(e).__name__, e)

# ensure built-in filters still take precedence
register_filter('name', lambda x: 'HIJACKED')

@prompt
def use_builtin(fn):
    '''{{ fn | name }}'''

def foo():
    pass

print(use_builtin(foo))
unregister_filter('name')
"
